#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <CL/cl.h>

struct Node {
    int starting;
    int no_of_edges;
};

const char* kernel_source = 
"struct Node {\n"
"    int starting;\n"
"    int no_of_edges;\n"
"};\n"
"\n"
"kernel void BFS_1(\n"
"    global const struct Node* h_graph_nodes,\n"
"    global const int* h_graph_edges,\n"
"    global char* h_graph_mask,\n"
"    global char* h_updating_graph_mask,\n"
"    global const char* h_graph_visited,\n"
"    global int* h_cost,\n"
"    const int no_of_nodes\n"
") {\n"
"    int tid = get_global_id(0);\n"
"    if (tid >= no_of_nodes) return;\n"
"\n"
"    if (h_graph_mask[tid] == 1) {\n"
"        h_graph_mask[tid] = 0;\n"
"        int start = h_graph_nodes[tid].starting;\n"
"        int end = start + h_graph_nodes[tid].no_of_edges;\n"
"\n"
"        for (int i = start; i < end; i++) {\n"
"            int id = h_graph_edges[i];\n"
"            if (h_graph_visited[id] == 0) {\n"
"                h_cost[id] = h_cost[tid] + 1;\n"
"                h_updating_graph_mask[id] = 1;\n"
"            }\n"
"        }\n"
"    }\n"
"}\n"
"\n"
"kernel void BFS_2(\n"
"    global char* h_graph_mask,\n"
"    global char* h_updating_graph_mask,\n"
"    global char* h_graph_visited,\n"
"    global char* stop,\n"
"    const int no_of_nodes\n"
") {\n"
"    int tid = get_global_id(0);\n"
"    if (tid >= no_of_nodes) return;\n"
"\n"
"    if (h_updating_graph_mask[tid] == 1) {\n"
"        h_graph_mask[tid] = 1;\n"
"        h_graph_visited[tid] = 1;\n"
"        *stop = 1;\n"
"        h_updating_graph_mask[tid] = 0;\n"
"    }\n"
"}\n";

void check_error(cl_int err, const char* msg) {
    if (err != CL_SUCCESS) {
        fprintf(stderr, "Error: %s (%d)\n", msg, err);
        exit(1);
    }
}

int main(int argc, char** argv) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char *input_f;

    if(argc != 3){
        fprintf(stderr,"Usage: %s <num_threads> <input_file>\n", argv[0]);
        exit(0);
    }

    input_f = argv[2];

    printf("Reading File\n");

    FILE *fp = fopen(input_f,"r");
    if(!fp) {
        printf("Error Reading graph file\n");
        return 1;
    }

    int source = 0;
    if (fscanf(fp,"%d",&no_of_nodes) != 1) {
        printf("Error reading no_of_nodes\n");
        fclose(fp);
        return 1;
    }

    Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
    char *h_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
    char *h_updating_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
    char *h_graph_visited = (char*) malloc(sizeof(char)*no_of_nodes);

    int start, edgeno;   
    for(int i = 0; i < no_of_nodes; i++) {
        if (fscanf(fp,"%d %d",&start,&edgeno) != 2) {
            printf("Error reading node %d\n", i);
            break;
        }
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i]=0;
        h_updating_graph_mask[i]=0;
        h_graph_visited[i]=0;
    }

    if (fscanf(fp,"%d",&source) != 1) {
        printf("Error reading source\n");
        fclose(fp);
        return 1;
    }

    h_graph_mask[source]=1;
    h_graph_visited[source]=1;

    if (fscanf(fp,"%d",&edge_list_size) != 1) {
        printf("Error reading edge_list_size\n");
        fclose(fp);
        return 1;
    }

    int id,cost;
    int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
    for(int i=0; i < edge_list_size ; i++) {
        if (fscanf(fp,"%d",&id) != 1) break;
        if (fscanf(fp,"%d",&cost) != 1) break;
        h_graph_edges[i] = id;
    }

    if(fp) fclose(fp);    

    int* h_cost = (int*) malloc( sizeof(int)*no_of_nodes);
    for(int i=0;i<no_of_nodes;i++) h_cost[i]=-1;
    h_cost[source]=0;

    printf("Start traversing the tree\n");

    // OpenCL Setup
    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue queue;
    cl_program program;
    cl_kernel kernel1, kernel2;

    cl_int err;
    err = clGetPlatformIDs(1, &platform, NULL);
    check_error(err, "clGetPlatformIDs");

    err = clGetDeviceIDs(platform, CL_DEVICE_TYPE_DEFAULT, 1, &device, NULL);
    check_error(err, "clGetDeviceIDs");

    cl_context_properties props[] = {CL_CONTEXT_PLATFORM, (cl_context_properties)platform, 0};
    context = clCreateContext(props, 1, &device, NULL, NULL, &err);
    check_error(err, "clCreateContext");

    queue = clCreateCommandQueue(context, device, 0, &err);
    check_error(err, "clCreateCommandQueue");

    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &err);
    check_error(err, "clCreateProgramWithSource");

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    check_error(err, "clBuildProgram");

    kernel1 = clCreateKernel(program, "BFS_1", &err);
    check_error(err, "clCreateKernel BFS_1");
    kernel2 = clCreateKernel(program, "BFS_2", &err);
    check_error(err, "clCreateKernel BFS_2");

    // Buffers
    cl_mem d_nodes = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(Node)*no_of_nodes, h_graph_nodes, &err);
    check_error(err, "d_nodes");
    cl_mem d_edges = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(int)*edge_list_size, h_graph_edges, &err);
    check_error(err, "d_edges");
    cl_mem d_mask = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char)*no_of_nodes, h_graph_mask, &err);
    check_error(err, "d_mask");
    cl_mem d_updating = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char)*no_of_nodes, h_updating_graph_mask, &err);
    check_error(err, "d_updating");
    cl_mem d_visited = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char)*no_of_nodes, h_graph_visited, &err);
    check_error(err, "d_visited");
    cl_mem d_cost = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(int)*no_of_nodes, h_cost, &err);
    check_error(err, "d_cost");

    char stop_flag = 1;
    cl_mem d_stop = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char), &stop_flag, &err);
    check_error(err, "d_stop");

    size_t global_size = (size_t)no_of_nodes;

    do {
        stop_flag = 0;
        clEnqueueWriteBuffer(queue, d_stop, CL_TRUE, 0, sizeof(char), &stop_flag, 0, NULL, NULL);

        // Kernel 1
        clSetKernelArg(kernel1, 0, sizeof(d_nodes), &d_nodes);
        clSetKernelArg(kernel1, 1, sizeof(d_edges), &d_edges);
        clSetKernelArg(kernel1, 2, sizeof(d_mask), &d_mask);
        clSetKernelArg(kernel1, 3, sizeof(d_updating), &d_updating);
        clSetKernelArg(kernel1, 4, sizeof(d_visited), &d_visited);
        clSetKernelArg(kernel1, 5, sizeof(d_cost), &d_cost);
        clSetKernelArg(kernel1, 6, sizeof(int), &no_of_nodes);

        clEnqueueNDRangeKernel(queue, kernel1, 1, NULL, &global_size, NULL, 0, NULL, NULL);

        // Kernel 2
        clSetKernelArg(kernel2, 0, sizeof(d_mask), &d_mask);
        clSetKernelArg(kernel2, 1, sizeof(d_updating), &d_updating);
        clSetKernelArg(kernel2, 2, sizeof(d_visited), &d_visited);
        clSetKernelArg(kernel2, 3, sizeof(d_stop), &d_stop);
        clSetKernelArg(kernel2, 4, sizeof(int), &no_of_nodes);

        clEnqueueNDRangeKernel(queue, kernel2, 1, NULL, &global_size, NULL, 0, NULL, NULL);

        clEnqueueReadBuffer(queue, d_stop, CL_TRUE, 0, sizeof(char), &stop_flag, 0, NULL, NULL);

    } while(stop_flag);

    clFinish(queue);

    // Read back cost
    clEnqueueReadBuffer(queue, d_cost, CL_TRUE, 0, sizeof(int)*no_of_nodes, h_cost, 0, NULL, NULL);

    printf("Compute time: 0.000000\n");

    FILE *fpo = fopen("result.txt","w");
    if (!fpo) {
        printf("Error opening result.txt\n");
    } else {
        for(int i=0;i<no_of_nodes;i++)
            fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
        fclose(fpo);
        printf("Result stored in result.txt\n");
    }

    // Cleanup
    clReleaseMemObject(d_nodes);
    clReleaseMemObject(d_edges);
    clReleaseMemObject(d_mask);
    clReleaseMemObject(d_updating);
    clReleaseMemObject(d_visited);
    clReleaseMemObject(d_cost);
    clReleaseMemObject(d_stop);
    clReleaseKernel(kernel1);
    clReleaseKernel(kernel2);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);

    return 0;
}
